#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding oncology-assessment (16 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    first_name:string! \
    last_name:string! \
    date_of_birth:date \
    sex:string! \
    phone:string! \
    email:string! \
    address:text! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    --htmx

cargo loco generate scaffold assessment_cancer_diagnosis \
    assessment:references \
    cancer_type:string! \
    cancer_site:string! \
    histology:string! \
    histology_other:string! \
    date_of_diagnosis:date \
    stage:string! \
    tnm_t:string! \
    tnm_n:string! \
    tnm_m:string! \
    grade:string! \
    laterality:string! \
    metastatic_sites:text! \
    biomarkers:text! \
    genetic_mutations:text! \
    diagnosis_notes:text! \
    --htmx

cargo loco generate scaffold assessment_treatment_history \
    assessment:references \
    has_prior_surgery:string! \
    surgery_details:text! \
    has_prior_radiation:string! \
    radiation_details:text! \
    has_prior_chemotherapy:string! \
    chemotherapy_details:text! \
    has_prior_immunotherapy:string! \
    immunotherapy_details:text! \
    has_prior_hormone_therapy:string! \
    hormone_therapy_details:text! \
    has_prior_targeted_therapy:string! \
    targeted_therapy_details:text! \
    has_clinical_trial_participation:string! \
    clinical_trial_details:text! \
    best_response:string! \
    treatment_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_treatment \
    assessment:references \
    treatment_intent:string! \
    current_regimen:string! \
    cycle_number:int \
    total_planned_cycles:int \
    last_treatment_date:date \
    next_treatment_date:date \
    treatment_modifications:text! \
    dose_reductions:string! \
    dose_reduction_details:text! \
    treatment_delays:string! \
    treatment_delay_details:text! \
    current_response:string! \
    supportive_care:text! \
    current_treatment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_symptom_assessment \
    assessment:references \
    pain_severity:int \
    pain_location:text! \
    pain_character:text! \
    fatigue_severity:int \
    nausea_severity:int \
    vomiting_frequency:string! \
    appetite_level:string! \
    dyspnoea_severity:int \
    constipation_severity:int \
    diarrhoea_severity:int \
    insomnia_severity:int \
    cognitive_changes:string! \
    cognitive_changes_details:text! \
    other_symptoms:text! \
    symptom_notes:text! \
    --htmx

cargo loco generate scaffold assessment_side_effects \
    assessment:references \
    has_haematological_toxicity:string! \
    neutropenia_grade:string! \
    anaemia_grade:string! \
    thrombocytopenia_grade:string! \
    has_dermatological_toxicity:string! \
    dermatological_details:text! \
    has_neuropathy:string! \
    neuropathy_grade:string! \
    neuropathy_details:text! \
    has_hepatotoxicity:string! \
    hepatotoxicity_details:text! \
    has_nephrotoxicity:string! \
    nephrotoxicity_details:text! \
    has_cardiotoxicity:string! \
    cardiotoxicity_details:text! \
    has_mucositis:string! \
    mucositis_grade:string! \
    alopecia:string! \
    other_side_effects:text! \
    side_effects_notes:text! \
    --htmx

cargo loco generate scaffold assessment_laboratory_results \
    assessment:references \
    lab_date:date \
    haemoglobin:double \
    white_cell_count:double \
    neutrophil_count:double \
    platelet_count:int \
    creatinine:double \
    egfr:double \
    bilirubin:double \
    alt:double \
    ast:double \
    alkaline_phosphatase:double \
    albumin:double \
    ldh:double \
    tumour_markers:text! \
    other_results:text! \
    laboratory_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    polypharmacy_concern:string! \
    drug_interactions_identified:string! \
    drug_interaction_details:text! \
    complementary_medicines:string! \
    complementary_medicine_details:text! \
    medication_adherence:string! \
    medications_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    indication:string! \
    start_date:date \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_psychosocial \
    assessment:references \
    anxiety_level:string! \
    depression_level:string! \
    distress_thermometer_score:int \
    coping_ability:string! \
    social_support:string! \
    financial_concerns:string! \
    financial_concerns_details:text! \
    employment_impact:string! \
    relationship_impact:string! \
    spiritual_concerns:string! \
    spiritual_concerns_details:text! \
    psychological_support_in_place:string! \
    psychological_support_details:text! \
    advance_care_planning_discussed:string! \
    psychosocial_notes:text! \
    --htmx

cargo loco generate scaffold assessment_functional_nutritional \
    assessment:references \
    ecog_performance_status:int \
    karnofsky_score:int \
    mobility_level:string! \
    adl_independence:string! \
    weight_change:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    nutritional_risk:string! \
    oral_intake:string! \
    nutritional_support:string! \
    dietitian_referral:string! \
    functional_nutritional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    ecog_score:int! \
    ecog_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
